"use strict";(self.webpackChunkronamosa_github_io=self.webpackChunkronamosa_github_io||[]).push([[60001],{28453:(e,t,o)=>{o.d(t,{R:()=>s,x:()=>i});var a=o(96540);const n={},r=a.createContext(n);function s(e){const t=a.useContext(r);return a.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function i(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:s(e.components),a.createElement(r.Provider,{value:t},e.children)}},41613:(e,t,o)=>{o.r(t),o.d(t,{assets:()=>h,contentTitle:()=>i,default:()=>u,frontMatter:()=>s,metadata:()=>a,toc:()=>l});var a=o(53235),n=o(74848),r=o(28453);const s={title:"What I\u2019ve Learned About Good Leaders, Bad Leaders in My Time in Technology.",author:"Ron Amosa",author_title:"Platform Security Engineer @ Salesforce U.S.",author_url:"https://github.com/ronamosa",author_image_url:"https://github.com/ronamosa.png",tags:["career"]},i=void 0,h={authorsImageUrls:[void 0]},l=[{value:"The Early Days",id:"the-early-days",level:2},{value:"Bad Leaders",id:"bad-leaders",level:2},{value:"Under the Bus",id:"under-the-bus",level:2},{value:"Grow a Pair",id:"grow-a-pair",level:2},{value:"Good leaders",id:"good-leaders",level:2},{value:"Lead, through service",id:"lead-through-service",level:2},{value:"There can, and must be, only one",id:"there-can-and-must-be-only-one",level:2},{value:"Conclusion",id:"conclusion",level:2}];function d(e){const t={blockquote:"blockquote",em:"em",h2:"h2",p:"p",strong:"strong",...(0,r.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.p,{children:"In recent times the issue of leadership has been a factor in the quality and felt experience of projects I have been across in my contracting career. These have ranged from feeling like everyone's a leader, having their own say and ideas on where the project should be going, to completely zero ideas on what the team is doing and everyone suddenly wants to know what the floor looks like when they're asked who's supposed to be doing what."}),"\n",(0,n.jsx)(t.h2,{id:"the-early-days",children:"The Early Days"}),"\n",(0,n.jsx)(t.p,{children:"I'm not one who's always respected authority, or leadership outright. Maybe because I've always understood the importance of leadership in any collective objective, and that leadership not done right can mean a lot of wrongs for the team, the project, and also at the individual level."}),"\n",(0,n.jsxs)(t.p,{children:['I\'ve experienced leadership "by default", i.e. parents, older siblings, people who you just accepted to be the leaders of your group, family etc. And in my experience, this showed me that just because you were in the "position" of leadership, does not mean you ',(0,n.jsx)(t.em,{children:"are"})," a leader - or more pointedly, ",(0,n.jsx)(t.strong,{children:"should"})," you be."]}),"\n",(0,n.jsx)(t.h2,{id:"bad-leaders",children:"Bad Leaders"}),"\n",(0,n.jsx)(t.p,{children:'Over the years and through many companies, I\'ve been exposed to "leaders" of all stripes and colours. A bad leader is not something I recognized straight away, or even knew what a bad leader looked like. But over time, and after being able to recognize engineering, or operational or design mistakes that lead to a bad outcome, slowly but surely a more ephemeral cause of bad outcomes started to identity itself. That\'s probably a little overly dramatic because it wasn\'t always super subtle when it came to identifying that "bad leadership" was happening.'}),"\n",(0,n.jsx)(t.p,{children:"For example, a manager not managing a toxic employee so that person negatively affects the rest of the team resulting in people avoiding coming to work, or being too afraid to make mistakes in case of being bullied that they freeze up and other people have to come in to help out. That, is clearly some bad leadership."}),"\n",(0,n.jsx)(t.h2,{id:"under-the-bus",children:"Under the Bus"}),"\n",(0,n.jsxs)(t.p,{children:["Team leaders are little bit different to managers, but all the same, they are in a leadership position. They're ",(0,n.jsx)(t.em,{children:"in"})," the actual team doing stuff, and usually have the technical experience to back up their ideas, thoughts etc. I've known team leaders to, in a panic when they've been put on the spot during a project meeting, immediately throw me under the bus in an effort to save their own ass (i.e. just not \"look bad\"). You only need to do this once (with me at least) and I'm not trusting you or your brand of leadership again anytime soon."]}),"\n",(0,n.jsxs)(t.p,{children:["Being the leader means ",(0,n.jsx)(t.em,{children:"owning"})," the decisions made, and the resulting work."]}),"\n",(0,n.jsx)(t.h2,{id:"grow-a-pair",children:"Grow a Pair"}),"\n",(0,n.jsx)(t.p,{children:'A more subtle that erodes this trust in the "leadership" is during periods of an insane amount of work going on, and too few engineers to do the work. You\'re under pressure, and being pulled in a thousand different directions. There are only so many hours in the week, and you have been battling one project manager after another to explain the simple math of a 50 hour work week to them, but are failing due to having a lot of work on, and not much brain capacity to deal with "managing" people and their unreasonable expectations.'}),"\n",(0,n.jsx)(t.p,{children:"So you turn to your manager to help. Help you by fighting this fight for you, by talking to the higher ups and alleviating some pressure because surely your manager can sell the fact there is only one person here doing this work, doing 50+ hours a week and he's quickly burning out."}),"\n",(0,n.jsx)(t.p,{children:"If your manager comes back with \"okay, we've decided we're going to try and figure out how you can provide all the work we need from you, to the deadlines, and with no overtime pay because its not in the budget\"..."}),"\n",(0,n.jsx)(t.p,{children:"If you get this result - your manager couldn't fight their way out of a wet paper bag, and you should probably find another team asap."}),"\n",(0,n.jsxs)(t.p,{children:["Bad leaders ",(0,n.jsx)(t.em,{children:"allow"})," bad things to happen because that's what leadership does. It's tasked with understanding the people, projects and business outcomes for the team and seek to serve these purposes."]}),"\n",(0,n.jsxs)(t.p,{children:["So when the leaders ",(0,n.jsx)(t.strong,{children:"fail"})," to do these things, either through ignorance or sheer incompetence, bad things are allowed to happen."]}),"\n",(0,n.jsx)(t.h2,{id:"good-leaders",children:"Good leaders"}),"\n",(0,n.jsx)(t.p,{children:"Sometimes when writing about everything that's gone badly from a leadership perspective in my IT career, I can easily forget the good leaders I have worked with and have shown through their actions what good leadership looks like."}),"\n",(0,n.jsx)(t.p,{children:"I had a manager who fought HR for me because he believed I deserved a second chance and that my past mistakes, irrelevant to my current position, shouldn't be held against me. He used his influence and position to negotiate and save my job. I'm not saying a good leader necessarily just gets you \"out of jail free\", but they are one that can assess a situation, make a values-based call on the matter and then back that decision up through action, to a successful result."}),"\n",(0,n.jsx)(t.p,{children:"I've worked with a particular Project Manager who really motivated and sought to understand not only what the business wanted out of the project team, but also how the project team thought and felt about the project. How the team was dealing with business requirement changes, and other pressures that were going on. He would trust his team to work on the problems and check in only when it was absolutely necessary to disturb the work with offers to chase up other resources if he needed me to have him commandeer that."}),"\n",(0,n.jsx)(t.p,{children:'I know a DevOps Manager who stands up for her team in a big room full of executive level suits. She asks the hard questions point blank drawing the disdain of these "important" people in order to communicate the negative effects these people were having to the work "on the ground". She would go immediately at the "problem managers" everyone knew were the roadblock and would be fearless in the face of company politics for the greater good of what her team was trying to achieve - for the company.'}),"\n",(0,n.jsx)(t.p,{children:"This is (imo) good leadership."}),"\n",(0,n.jsx)(t.h2,{id:"lead-through-service",children:"Lead, through service"}),"\n",(0,n.jsx)(t.p,{children:"leadership is not standing over everyone barking orders at them and then telling the rest of the company how well you did. well, good leadership at least (imo). There is an iconic Samoan proverb that goes"}),"\n",(0,n.jsxs)(t.blockquote,{children:["\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:'"O le ala ole pule, o le tautua".'})}),"\n"]}),"\n",(0,n.jsxs)(t.p,{children:["Which translates to ",(0,n.jsx)(t.em,{children:'"The way to leadership (authority), is through service."'})]}),"\n",(0,n.jsx)(t.p,{children:'And that\'s my take on leadership as well- that a leader is someone who is there to "serve" the team, to "serve" the needs of the project. So that whatever is required, by the team or the project can be managed, co-ordinated, understood, resolved i.e. served, by the leader (in conjunction with the team of course).'}),"\n",(0,n.jsx)(t.p,{children:'The old model was that the manager aka leader was "in charge" and the team worked for this direct leader. And this fits in with the "old world" view that gave us silos, and sort of "protectionist" teams who draw lines between their work and yours.'}),"\n",(0,n.jsx)(t.p,{children:'Not only is that mode outdated, I think it collides with the way the new world of DevOps, of Cross-functional teams, needs to work. I think I\'ve made the "microservices" analogy in another post, but we should all be working together like microservices for the same overall "application" (not sure the analogy holds here, but its 10pm and I need to finish this post)'}),"\n",(0,n.jsx)(t.h2,{id:"there-can-and-must-be-only-one",children:"There can, and must be, only one"}),"\n",(0,n.jsx)(t.p,{children:'Lack of leadership is it\'s own issue. Especially in tech, where there are "a lot of smart people", people managers may be forgiven for thinking they can leave a group of "smart people" together and they should be able to suss out a consensus on a direction, tasks and work involved for the project.'}),"\n",(0,n.jsxs)(t.blockquote,{children:["\n",(0,n.jsx)(t.p,{children:"\"We don't need a leader right? We'll just have a few meetings, make a few decisions and everyone can get to work.\""}),"\n"]}),"\n",(0,n.jsxs)(t.p,{children:["People think they can \"share\" a leadership. And I'm sure there's going to be a use case for exactly that out there in the wild, but in my experience, there needs to be ",(0,n.jsx)(t.em,{children:"a"}),' leader - one. Now if you\'ve been following along with this post you would push the completely understandable knee-jerk reaction idea of a dictatorial leader who everyone has to listen to, out of your minds, and see that there has to be someone to take the responsibility of "serving" the project by doing this job.']}),"\n",(0,n.jsx)(t.p,{children:"The job of understanding the project, the business reasons, the team, the team dynamics, the technical effort etc all in an effort to do the mental and emotional work of figuring out the best course of action, based on the consulting with all stakeholders (the product owner, the business, and especially the project team), making the decisions, and then seeing these things through."}),"\n",(0,n.jsx)(t.h2,{id:"conclusion",children:"Conclusion"}),"\n",(0,n.jsx)(t.p,{children:"I was going to write a conclusion, but I think there's only really a few ideas here and I've covered them pretty thoroughly so I think my conclusion will be brief."}),"\n",(0,n.jsx)(t.p,{children:"Bad leadership, other than being blatantly experienced through bad decisions that directly affect your work and workload, can also be felt in an \"overall\" sense of morale, 'safety' and level of trust felt by the team towards those people recognized as the 'leadership'."}),"\n",(0,n.jsxs)(t.p,{children:["Good leadership exists and can be seen in selflessness, servitude and genuine empathy of the team, the project, and the personal experiences of the ",(0,n.jsx)(t.em,{children:"humans"})," involved in the busineses. Good leadership leads through service. Its unselfish."]}),"\n",(0,n.jsx)(t.p,{children:'While we might not all believe in having ONE leader, it\'s fair to say that a minimum of ONE is required. This person is not "the boss". We understand the leader to be of service to the team. To take on the intangible, non-functional aspects of the workloads the team must take on, and do this "for the team".'}),"\n",(0,n.jsx)(t.p,{children:"Overall, leadership makes its mark on your everyday work life whether you're aware of it or not. And these are just some of my thoughts on the subject."})]})}function u(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(d,{...e})}):d(e)}},53235:e=>{e.exports=JSON.parse('{"permalink":"/blog/2019/12/01/Thoughts-on-Leadership","editUrl":"https://github.com/ronamosa/ronamosa.github.io/edit/main/website/blog/2019-12-01-Thoughts-on-Leadership.md","source":"@site/blog/2019-12-01-Thoughts-on-Leadership.md","title":"What I\u2019ve Learned About Good Leaders, Bad Leaders in My Time in Technology.","description":"In recent times the issue of leadership has been a factor in the quality and felt experience of projects I have been across in my contracting career. These have ranged from feeling like everyone\'s a leader, having their own say and ideas on where the project should be going, to completely zero ideas on what the team is doing and everyone suddenly wants to know what the floor looks like when they\'re asked who\'s supposed to be doing what.","date":"2019-12-01T00:00:00.000Z","tags":[{"inline":true,"label":"career","permalink":"/blog/tags/career"}],"readingTime":8.47,"hasTruncateMarker":true,"authors":[{"name":"Ron Amosa","title":"Platform Security Engineer @ Salesforce U.S.","url":"https://github.com/ronamosa","imageURL":"https://github.com/ronamosa.png","key":null,"page":null}],"frontMatter":{"title":"What I\u2019ve Learned About Good Leaders, Bad Leaders in My Time in Technology.","author":"Ron Amosa","author_title":"Platform Security Engineer @ Salesforce U.S.","author_url":"https://github.com/ronamosa","author_image_url":"https://github.com/ronamosa.png","tags":["career"]},"unlisted":false,"prevItem":{"title":"Working Through the Holidays as a Contractor: Make Hay While the Sun Shines.","permalink":"/blog/2019/12/08/Working-through-the-Holidays"},"nextItem":{"title":"The True Cloud Revolution and How Its Disrupting the Whole Organization.","permalink":"/blog/2019/11/24/Battling-the-Cloud-World"}}')}}]);